// ── Utilidades de búsqueda ──

/** Busca CNO por código o descripción */
export function searchCNO(query: string, maxResults = 20): CNOCode[] {
  const q = query.toLowerCase().trim();
  return CNO_CATALOG
    .filter(c => c.code.includes(q) || c.description.toLowerCase().includes(q))
    .slice(0, maxResults);
}

/** Obtiene un CNO por código exacto */
export function getCNOByCode(code: string): CNOCode | undefined {
  return CNO_CATALOG.find(c => c.code === code);
}

/** Obtiene los 10 grandes grupos */
export function getCNOGroups(): CNOCode[] {
  return CNO_CATALOG.filter(c => c.groupLevel === 1);
}

/** Obtiene ocupaciones de un grupo */
export function getCNOByGroup(groupCode: string): CNOCode[] {
  return CNO_CATALOG.filter(c => c.parentCode === groupCode && c.groupLevel === 4);
}

export default CNO_CATALOG;